#!/bin/bash
# code/04_apply_fdr.sh
# Applies Benjamini-Hochberg FDR correction to GWAS raw results.
#
# Input: data/interim/gwas_raw.tsv (generated by code/03_gwas.sh)
# Output: data/processed/gwas_results_fdr.tsv
#
# Dependencies: code/utils/fdr_correction.py (T020)
#
# This script enforces FR-004 (FDR correction) and FR-005 (Threshold sensitivity).
# It must be invoked after T017 (GWAS execution) and T021 (Threshold sensitivity).

set -e

# Configuration
INPUT_FILE="data/interim/gwas_raw.tsv"
OUTPUT_FILE="data/processed/gwas_results_fdr.tsv"
SCRIPT_PATH="code/utils/fdr_correction.py"

# Verify input exists
if [ ! -f "$INPUT_FILE" ]; then
    echo "ERROR: Input file not found: $INPUT_FILE"
    echo "Please ensure code/03_gwas.sh (T017) has been executed successfully."
    exit 1
fi

# Verify script exists
if [ ! -f "$SCRIPT_PATH" ]; then
    echo "ERROR: FDR correction script not found: $SCRIPT_PATH"
    exit 1
fi

# Ensure output directory exists
mkdir -p "$(dirname "$OUTPUT_FILE")"

echo "Starting FDR correction pipeline..."
echo "Input: $INPUT_FILE"
echo "Output: $OUTPUT_FILE"

# Execute FDR correction
python "$SCRIPT_PATH" \
    --input "$INPUT_FILE" \
    --output "$OUTPUT_FILE" \
    --p-col "P" \
    --q-col "Q"

# Verify output was created
if [ ! -f "$OUTPUT_FILE" ]; then
    echo "ERROR: FDR correction failed to produce output file: $OUTPUT_FILE"
    exit 1
fi

# Report results
echo "FDR correction completed successfully."
echo "Output written to: $OUTPUT_FILE"

# Display summary of significant SNPs
echo ""
echo "Summary of significant SNPs (q < 0.05):"
grep -v "^#" "$OUTPUT_FILE" | awk -F'\t' 'NR==1 {for(i=1;i<=NF;i++) if($i=="significant") col=i} NR>1 && $col=="True" {count++} END {print "Count:", count+0}'

echo ""
echo "Pipeline step T022 complete."